String _buildSingleBookingHtml(
  Booking booking,
  BookingPrintVariant variant,
  List<Booking> relatedArtistBookings,
  List<BookingDisplayEntry> relatedArtistEntries,
  BookingDisplayEntry? selectedArtistEntry,
  String artistName,
) {
  final isClientCopy = variant == BookingPrintVariant.clientInvoice || variant == BookingPrintVariant.clientConfirmation;
  final isArtistCopy = variant == BookingPrintVariant.artist;
  
  if (isClientCopy) {
    return _buildClientConfirmationHtml(booking, variant);
  }
  final addonTotal = _addonTotal(booking);
  final activeArtistEntry = selectedArtistEntry ?? booking.displayEntries.first;
  final activeEntryAssignments = booking.bookingItems.isNotEmpty
      ? activeArtistEntry.assignedStaff
      : (activeArtistEntry.assignedStaff.isNotEmpty
            ? activeArtistEntry.assignedStaff
            : booking.assignedStaff);
  final effectiveArtistEntries = relatedArtistEntries.isNotEmpty
      ? relatedArtistEntries.toList()
      : relatedArtistBookings
            .expand((item) => item.displayEntries)
            .where((entry) => entry.assignedStaff.isNotEmpty)
            .toList();
  effectiveArtistEntries.sort(
    (a, b) => a.serviceStart.compareTo(b.serviceStart),
  );
  final entryBookingDate = activeArtistEntry.selectedDates.isNotEmpty
      ? activeArtistEntry.selectedDates.first
      : booking.bookingDate;
  final entryDiscountAmount = booking.discountAmount;
  final entryDiscountLabel = booking.discountType == 'percent'
      ? '${booking.discountValue.toStringAsFixed(0)}%'
      : 'INR ${booking.discountValue.toStringAsFixed(0)}';
  final entryTotalAmount = (booking.bookingItems.isEmpty
          ? activeArtistEntry.totalPrice
          : activeArtistEntry.totalPrice + addonTotal)
      .toDouble();
  final entryPackageAmount = _packageAmountFromTotal(
    entryTotalAmount,
    addonTotal,
  );
  final entryForecast =
      entryTotalAmount - activeArtistEntry.advanceAmount - entryDiscountAmount;

  final assignedStaffRows = activeEntryAssignments.isEmpty
      ? '<tr><td colspan="3">No staff assigned</td></tr>'
      : activeEntryAssignments
            .map(
              (staff) =>
                  '''
<tr>
  <td>${_escape(staff.artistName)}</td>
  <td>${_escape(_staffWorkLabel(staff))}</td>
  <td>${_escape(staff.type)}</td>
</tr>''',
            )
            .join();

  final addonRows = booking.addons.isEmpty
      ? '<tr><td colspan="4">No add-ons</td></tr>'
      : booking.addons
            .map(
              (addon) =>
                  '''
<tr>
  <td>${_escape(addon.service)}</td>
  <td>${addon.persons}</td>
  <td>INR ${addon.amount.toStringAsFixed(0)}</td>
  <td>INR ${(addon.amount * addon.persons).toStringAsFixed(0)}</td>
</tr>''',
            )
            .join();

  final statusLabel = booking.status.isEmpty
      ? 'Pending'
      : _titleCase(booking.status);
  final logisticsRows = [
    _detailRow('Region', booking.region),
    _detailRow('Driver', booking.driverName),
    _detailRow('Travel Mode', booking.travelMode),
    _detailRow('Travel Time', booking.travelTime),
    _detailRow(
      'Travel Distance',
      booking.travelDistanceKm > 0
          ? '${booking.travelDistanceKm.toStringAsFixed(0)} KM'
          : '',
    ),
    _detailRow('Address', booking.address),
    _detailRow('Pincode', booking.pincode),
    _detailRow('Map URL', booking.mapUrl),
    _detailRow('Room Detail', booking.requiredRoomDetail),
    _detailRow('Secondary Contact', booking.secondaryContact),
  ].where((row) => row.isNotEmpty).join();

  final serviceRows = [
    _detailRow('Outfit Details', booking.outfitDetails),
    _detailRow('Capture Staff', booking.captureStaffDetails),
    _detailRow(
      'Content Creation Required',
      booking.contentCreationRequired ? 'Yes' : 'No',
    ),
    _detailRow('Staff Instructions', booking.staffInstructions),
    _detailRow('Internal Remarks', booking.internalRemarks),
  ].where((row) => row.isNotEmpty).join();
  final clientRows = [
    _detailRow('Customer Name', booking.customerName),
    _detailRow('Primary Number', booking.phone),
    _detailRow('Alternative Number', booking.secondaryContact),
    _detailRow('Email', booking.email),
  ].where((row) => row.isNotEmpty).join();
  final artistRows = [
    _detailRow(
      'Assigned Artist(s)',
      activeEntryAssignments.isEmpty
          ? ''
          : activeEntryAssignments.map((staff) => staff.artistName).join(', '),
    ),
    _detailRow(
      'Artist Mobile Number',
      activeEntryAssignments
          .where((staff) => staff.phone.trim().isNotEmpty)
          .map((staff) => '${staff.artistName}: ${staff.phone}')
          .join(', '),
    ),
    _detailRow('Package', activeArtistEntry.service),
    _detailRow('Event Slot', activeArtistEntry.eventSlot),
    _detailRow('Status', statusLabel),
  ].where((row) => row.isNotEmpty).join();
  final title = isArtistCopy ? 'Artist Copy' : 'Client Copy';
  final subtitle = isArtistCopy
      ? 'Complete booking sheet for assigned team'
      : 'Booking confirmation copy for client';
  final effectiveArtistName = artistName.trim().isNotEmpty
      ? artistName.trim()
      : activeEntryAssignments
            .where((staff) => staff.roleType.toLowerCase() == 'lead')
            .map((staff) => staff.artistName.trim())
            .firstWhere((name) => name.isNotEmpty, orElse: () => '');
  final sortedArtistWorks = effectiveArtistEntries;
  final artistWorkRows = sortedArtistWorks.isEmpty
      ? '<tr><td colspan="5">No other works scheduled for this artist today</td></tr>'
      : sortedArtistWorks.map((item) {
          final isCurrentBooking = item.id == activeArtistEntry.id;
          return '''
<tr>
  <td>${isCurrentBooking ? 'Current' : ''}</td>
  <td>${_formatTime(item.serviceStart)} - ${_formatTime(item.serviceEnd)}</td>
  <td>${_escape(item.booking.customerName)}</td>
  <td>${_escape(item.service)}</td>
  <td>${_escape(item.booking.region.isEmpty ? 'No region' : item.booking.region)}</td>
</tr>''';
        }).join();
  final artistClientDetailRows = sortedArtistWorks.isEmpty
      ? '<tr><td colspan="8">No client details available for this artist today</td></tr>'
      : sortedArtistWorks.map((item) {
          final isCurrentBooking = item.id == activeArtistEntry.id;
          return '''
<tr${isCurrentBooking ? ' class="current-work-row"' : ''}>
  <td>${isCurrentBooking ? '<span class="current-badge">Current</span>' : ''}</td>
  <td>${_formatTime(item.serviceStart)} - ${_formatTime(item.serviceEnd)}</td>
  <td>${_escape(item.booking.customerName)}</td>
  <td>${_escape(item.booking.phone)}</td>
  <td>${_escape(item.booking.secondaryContact.isEmpty ? '-' : item.booking.secondaryContact)}</td>
  <td>${_escape(item.booking.email.isEmpty ? '-' : item.booking.email)}</td>
  <td>${_escape(item.service)}</td>
  <td>${_escape(item.booking.region.isEmpty ? 'No region' : item.booking.region)}</td>
</tr>''';
        }).join();

  return '''
    <div class="header" style="display: flex; align-items: center; gap: 16px;">
      <img src="data:image/png;base64," style="width: 48px; height: 48px; object-fit: contain; border-radius: 8px;" />
      <div>
        <div class="title">Booking Details - $title</div>
        <p class="muted">$subtitle</p>
      </div>
    </div>

    <div class="grid">
      <div class="card">
        <div class="label">Customer</div>
        <div class="value">${_escape(booking.customerName)}</div>
        <p class="muted">${_escape(booking.phone)}${booking.email.isEmpty ? '' : ' • ${_escape(booking.email)}'}</p>
      </div>
      <div class="card">
        <div class="label">Service</div>
        <div class="value">${_escape(activeArtistEntry.service)}</div>
        <p class="muted">${_escape(booking.region.isEmpty ? 'No region selected' : booking.region)}${booking.driverName.isEmpty ? '' : ' • Driver: ${_escape(booking.driverName)}'}</p>
      </div>
      <div class="card">
        <div class="label">Event Date</div>
        <div class="value">${_formatDate(entryBookingDate)}</div>
        <p class="muted">${_formatTime(activeArtistEntry.serviceStart)} - ${_formatTime(activeArtistEntry.serviceEnd)}</p>
      </div>
      <div class="card">
        <div class="label">Booking ID</div>
        <div class="value">${_escape(booking.displayBookingNumber)}</div>
        <p class="muted">Status: ${_escape(statusLabel)}</p>
      </div>
    </div>

    <div class="section">
      <h3>Client Details</h3>
      <table class="detail-table">
        <tbody>
          ${clientRows.isEmpty ? '<tr><td colspan="2">No client details available</td></tr>' : clientRows}
        </tbody>
      </table>
    </div>

    <div class="section">
      <h3>Artist & Package Details</h3>
      <table class="detail-table">
        <tbody>
          ${artistRows.isEmpty ? '<tr><td colspan="2">No artist/package details available</td></tr>' : artistRows}
        </tbody>
      </table>
    </div>

    ${isArtistCopy ? '''
    <div class="section">
      <h3>Logistics & Location</h3>
      <table class="detail-table">
        <tbody>
          ${logisticsRows.isEmpty ? '<tr><td colspan="2">No logistics details added</td></tr>' : logisticsRows}
        </tbody>
      </table>
    </div>

    <div class="section">
      <h3>Service Specifics</h3>
      <table class="detail-table">
        <tbody>
          ${serviceRows.isEmpty ? '<tr><td colspan="2">No service-specific details added</td></tr>' : serviceRows}
        </tbody>
      </table>
    </div>
    ''' : ''}

    ${isArtistCopy ? '''
    <div class="section">
      <h3>Assigned Team</h3>
      <table>
        <thead>
          <tr><th>Name</th><th>Role</th><th>Type</th></tr>
        </thead>
        <tbody>
          $assignedStaffRows
        </tbody>
      </table>
    </div>

    <div class="section">
      <h3>Today's Artist Works</h3>
      <p class="schedule-note">${_escape(effectiveArtistName.isEmpty ? 'Assigned artist' : effectiveArtistName)} schedule for ${_formatDate(entryBookingDate)}, sorted by time.</p>
      <table>
        <thead>
          <tr><th>Current</th><th>Time</th><th>Client</th><th>Service</th><th>Region</th></tr>
        </thead>
        <tbody>
          $artistWorkRows
        </tbody>
      </table>
    </div>

    <div class="section">
      <h3>Today's Client Details</h3>
      <p class="schedule-note">Combined client sheet for all works assigned to ${_escape(effectiveArtistName.isEmpty ? 'this artist' : effectiveArtistName)} today.</p>
      <table>
        <thead>
          <tr><th>Current</th><th>Time</th><th>Client</th><th>Primary</th><th>Alternative</th><th>Email</th><th>Package</th><th>Region</th></tr>
        </thead>
        <tbody>
          $artistClientDetailRows
        </tbody>
      </table>
    </div>
    ''' : ''}

    <div class="section">
      <h3>Add-ons</h3>
      <table>
        <thead>
          <tr><th>Service</th><th>Persons</th><th>Rate</th><th>Total</th></tr>
        </thead>
        <tbody>
          $addonRows
        </tbody>
      </table>
    </div>

    <div class="summary">
      <div class="summary-row"><span>Package Amount</span><span>INR ${entryPackageAmount.toStringAsFixed(0)}</span></div>
      <div class="summary-row"><span>Add-ons</span><span>INR ${addonTotal.toStringAsFixed(0)}</span></div>
      <div class="summary-row"><span>Total Amount</span><span>INR ${entryTotalAmount.toStringAsFixed(0)}</span></div>
      <div class="summary-row"><span>Advance Paid</span><span>INR ${activeArtistEntry.advanceAmount.toStringAsFixed(0)}</span></div>
      <div class="summary-row"><span>Discount</span><span>$entryDiscountLabel</span></div>
      <div class="summary-row"><span>Applied Discount Amount</span><span>INR ${entryDiscountAmount.toStringAsFixed(0)}</span></div>
      <div class="summary-row"><strong>Forecast Balance</strong><strong>INR ${entryForecast.toStringAsFixed(0)}</strong></div>
    </div>
''';
}

String _buildClientConfirmationHtml(Booking booking, BookingPrintVariant variant) {
  // ── GST helpers ────────────────────────────────────────────────────────────
  double _gstBase(double incl) => double.parse((incl * 100.0 / 105.0).toStringAsFixed(2));
  double _gstCgst(double incl) => double.parse((incl * 2.5  / 105.0).toStringAsFixed(2));
  double _gstSgst(double incl) => double.parse((incl * 2.5  / 105.0).toStringAsFixed(2));
  String _inr(double v) => '₹${v.toStringAsFixed(2)}';

  // ── Booking info ────────────────────────────────────────────────────────────
  final addonTotal      = _addonTotal(booking);
  final packageAmount   = _packageAmountFromTotal(booking.totalPrice, addonTotal);
  final remainingBalance = booking.balanceDue;

  final invoiceDate = booking.bookingDate;
  final invoiceDateStr =
      '${invoiceDate.day.toString().padLeft(2, '0')}/${invoiceDate.month.toString().padLeft(2, '0')}/${invoiceDate.year}';

  final paymentMode = booking.paymentMode.trim().isNotEmpty
      ? _escape(booking.paymentMode.trim())
      : 'N/A';
  final hsnCode = booking.hsnCode.trim().isNotEmpty ? booking.hsnCode.trim() : '998361';

  final invoiceStatus = (booking.status.toLowerCase() == 'confirmed' ||
          booking.status.toLowerCase() == 'completed')
      ? 'APPROVED'
      : 'PENDING';
  final statusBadgeColor = invoiceStatus == 'APPROVED' ? '#15803d' : '#b45309';

  // ── Assigned artists ────────────────────────────────────────────────────────
  final allAssignments = <BookingAssignment>[];
  allAssignments.addAll(booking.assignedStaff);
  for (final item in booking.bookingItems) {
    allAssignments.addAll(item.assignedStaff);
  }
  final uniqueAssignments = <String, BookingAssignment>{};
  for (final a in allAssignments) {
    final key = a.employeeId.isNotEmpty ? a.employeeId : a.artistName;
    if (key.isNotEmpty) uniqueAssignments[key] = a;
  }
  final assignments = uniqueAssignments.values.toList();

  final leadArtists = assignments
      .where((a) =>
          a.roleType.toLowerCase() == 'lead' && a.artistName.trim().isNotEmpty)
      .map((a) => a.artistName.trim())
      .join(', ');
  final leadRoles = assignments
      .where((a) => a.roleType.toLowerCase() == 'lead')
      .map((a) => _staffWorkLabel(a))
      .where((r) => r.isNotEmpty)
      .join(', ');
  final leadPhone = assignments
      .where((a) =>
          a.roleType.toLowerCase() == 'lead' && a.phone.trim().isNotEmpty)
      .map((a) => a.phone.trim())
      .join(', ');

  // ── POC ─────────────────────────────────────────────────────────────────────
  final String pocName;
  final String pocPhone;
  if (booking.pocName.trim().isNotEmpty) {
    pocName = booking.pocName.trim();
    pocPhone = booking.pocPhone.trim();
  } else if (booking.pocId.trim().isNotEmpty) {
    final found = assignments.cast<BookingAssignment?>().firstWhere(
      (a) => a?.employeeId == booking.pocId,
      orElse: () => null,
    );
    pocName = found?.artistName.trim() ?? '';
    pocPhone = found?.phone.trim() ?? '';
  } else {
    pocName = '';
    pocPhone = '';
  }

  // ── Services table rows ─────────────────────────────────────────────────────
  final serviceRows = StringBuffer();
  // Main package row
  final pkgBase = _gstBase(packageAmount);
  final pkgCgst = _gstCgst(packageAmount);
  final pkgSgst = _gstSgst(packageAmount);
  serviceRows.write('''
<tr>
  <td>${_escape(booking.service)}</td>
  <td class="center">${_escape(hsnCode)}</td>
  <td class="right">${variant == BookingPrintVariant.clientConfirmation ? _inr(packageAmount) : _inr(pkgBase)}</td>
  ${variant == BookingPrintVariant.clientConfirmation ? "" : "<td class=\"right\">${_inr(pkgCgst)}</td><td class=\"right\">${_inr(pkgSgst)}</td>"}
  <td class="right fw600">${_inr(packageAmount)}</td>
</tr>''');
  // Add-on rows
  for (final addon in booking.addons) {
    final addonIncl  = addon.amount * addon.persons;
    final addonBase  = _gstBase(addonIncl);
    final addonCgst  = _gstCgst(addonIncl);
    final addonSgst  = _gstSgst(addonIncl);
    serviceRows.write('''
<tr>
  <td>${_escape(addon.service)}${addon.persons > 1 ? ' × ${addon.persons}' : ''}</td>
  <td class="center">${_escape(hsnCode)}</td>
  <td class="right">${variant == BookingPrintVariant.clientConfirmation ? _inr(addonIncl) : _inr(addonBase)}</td>
  ${variant == BookingPrintVariant.clientConfirmation ? "" : "<td class=\"right\">${_inr(addonCgst)}</td><td class=\"right\">${_inr(addonSgst)}</td>"}
  <td class="right fw600">${_inr(addonIncl)}</td>
</tr>''');
  }

  // ── Summary numbers ─────────────────────────────────────────────────────────
  final totalCgst = _gstCgst(booking.totalPrice);
  final totalSgst = _gstSgst(booking.totalPrice);
  final totalGst  = double.parse((totalCgst + totalSgst).toStringAsFixed(2));

  // ── Discount line ────────────────────────────────────────────────────────────
  final discountLine = booking.discountAmount > 0
      ? '''<tr class="sum-row"><td colspan="2" class="right sum-label">Discount</td><td class="right sum-val">– ${_inr(booking.discountAmount)}</td></tr>'''
      : '';

  // ── Artist card section ──────────────────────────────────────────────────────
  final artistNameLine = leadArtists.isNotEmpty
      ? '<div class="info-line"><span class="info-key">Artist</span> <span class="info-val">${_escape(leadArtists)}</span></div>'
      : '';
  final artistRoleLine = leadRoles.isNotEmpty
      ? '<div class="info-line"><span class="info-key">Role</span> <span class="info-val">${_escape(leadRoles)}</span></div>'
      : '';
  final artistPhoneLine = leadPhone.isNotEmpty
      ? '<div class="info-line"><span class="info-key">Contact</span> <span class="info-val">${_escape(leadPhone)}</span></div>'
      : '';
  final pocLine = pocName.isNotEmpty
      ? '<div class="info-line poc-line"><span class="info-key">POC</span> <span class="info-val">${_escape(pocName)}${pocPhone.isNotEmpty ? ' — ${_escape(pocPhone)}' : ''}</span></div>'
      : '';

  return '''
<div class="gst-invoice">

  <!-- ═══ HEADER ═══ -->
  <div class="inv-header">
    <div class="inv-brand">
      <div class="inv-logo-wrap">
        <img src="data:image/png;base64," alt="logo" style="width:64px;height:64px;object-fit:contain;" onerror="this.style.display='none'" />
      </div>
      <div>
        <div class="inv-company">TEAM N MAKEOVERS</div>
        <div class="inv-doc-type">${variant == BookingPrintVariant.clientConfirmation ? "ADVANCE RECEIPT" : "GST INVOICE"}</div>
      </div>
    </div>
    <div class="inv-meta-grid">
      <div class="inv-meta-cell">
        <span class="meta-label">INVOICE NO.</span>
        <span class="meta-val">${_escape(booking.displayBookingNumber)}</span>
      </div>
      <div class="inv-meta-cell">
        <span class="meta-label">DATE</span>
        <span class="meta-val">$invoiceDateStr</span>
      </div>
      <div class="inv-meta-cell">
        <span class="meta-label">STATUS</span>
        <span class="status-badge" style="background:${statusBadgeColor}">$invoiceStatus</span>
      </div>
    </div>
  </div>

  <!-- ═══ BILLED TO + ARTIST ═══ -->
  <div class="two-col-section">
    <div class="info-card">
      <div class="info-card-title">BILLED TO</div>
      <div class="info-customer">${_escape(booking.customerName)}</div>
      ${booking.phone.isNotEmpty ? '<div class="info-line"><span class="info-key">Phone</span> <span class="info-val">${_escape(booking.phone)}</span></div>' : ''}
      ${booking.secondaryContact.isNotEmpty ? '<div class="info-line"><span class="info-key">Alt. Phone</span> <span class="info-val">${_escape(booking.secondaryContact)}</span></div>' : ''}
      ${booking.email.isNotEmpty ? '<div class="info-line"><span class="info-key">Email</span> <span class="info-val">${_escape(booking.email)}</span></div>' : ''}
      ${booking.address.isNotEmpty ? '<div class="info-line"><span class="info-key">Address</span> <span class="info-val">${_escape(booking.address)}${booking.pincode.isNotEmpty ? ', ${_escape(booking.pincode)}' : ''}</span></div>' : ''}
      ${booking.district.isNotEmpty ? '<div class="info-line"><span class="info-key">District</span> <span class="info-val">${_escape(booking.district)}</span></div>' : ''}
    </div>
    ${variant == BookingPrintVariant.clientConfirmation ? '''<div class="info-card">
      <div class="info-card-title">YOUR ARTIST</div>
      $artistNameLine
      $artistRoleLine
      $artistPhoneLine
      $pocLine
      ${booking.eventSlot.isNotEmpty ? '<div class="info-line"><span class="info-key">Slot</span> <span class="info-val">${_escape(booking.eventSlot)}</span></div>' : ''}
    </div>''' : '''<div class="info-card">
      <div class="info-card-title">COMPANY DETAILS</div>
      <div class="info-customer">TEAM N MAKEOVERS</div>
      <div class="info-line"><span class="info-val" style="line-height: 1.5; color: #1f2937;">Kozhikode Kerala 673014<br>India</span></div>
      <div style="margin-top: 8px;"></div>
      <div class="info-line"><span class="info-key" style="min-width: 60px;">GSTIN</span> <span class="info-val">32AAJCN6432D1ZR</span></div>
      <div class="info-line"><span class="info-key" style="min-width: 60px;">Phone</span> <span class="info-val">9645424283</span></div>
      <div class="info-line"><span class="info-key" style="min-width: 60px;">Email</span> <span class="info-val">teamnfinance@gmail.com</span></div>
    </div>'''}
  </div>

  <!-- ═══ SERVICES TABLE ═══ -->
  <div class="section-title">SERVICES</div>
  <table class="gst-table">
    <thead>
      <tr>
        <th>SERVICE</th>
        <th class="center">HSN / SAC</th>
        <th class="right">${variant == BookingPrintVariant.clientConfirmation ? "RATE" : "BASE AMT"}</th>
        ${variant == BookingPrintVariant.clientConfirmation ? "" : "<th class=\"right\">CGST 2.5%</th>\n        <th class=\"right\">SGST 2.5%</th>"}
        <th class="right">${variant == BookingPrintVariant.clientConfirmation ? "AMOUNT" : "TOTAL (INCL. GST)"}</th>
      </tr>
    </thead>
    <tbody>
      ${serviceRows.toString()}
    </tbody>
  </table>

  <!-- ═══ PAYMENT SUMMARY ═══ -->
  <div class="summary-outer">
    <table class="summary-table">
      <tr class="sum-row">
        <td colspan="2" class="right sum-label">${variant == BookingPrintVariant.clientConfirmation ? "Subtotal" : "Subtotal (Incl. GST)"}</td>
        <td class="right sum-val">${_inr(booking.totalPrice)}</td>
      </tr>
      ${variant == BookingPrintVariant.clientConfirmation ? "" : '''<tr class="sum-row gst-breakdown-row">
        <td class="right sum-label sub-indent" colspan="2">CGST @ 2.5%</td>
        <td class="right sum-val sub-val">${_inr(totalCgst)}</td>
      </tr>
      <tr class="sum-row gst-breakdown-row">
        <td class="right sum-label sub-indent" colspan="2">SGST @ 2.5%</td>
        <td class="right sum-val sub-val">${_inr(totalSgst)}</td>
      </tr>
      <tr class="sum-row">
        <td colspan="2" class="right sum-label">Total GST</td>
        <td class="right sum-val">${_inr(totalGst)}</td>
      </tr>'''}
      $discountLine
      <tr class="sum-row">
        <td colspan="2" class="right sum-label">Advance Paid</td>
        <td class="right sum-val">${_inr(booking.advanceAmount)}</td>
      </tr>
      <tr class="balance-due-row">
        <td colspan="2" class="right balance-label">BALANCE DUE</td>
        <td class="right balance-val">${_inr(remainingBalance)}</td>
      </tr>
    </table>
  </div>

  <!-- ═══ FOOTER ═══ -->
  <div class="inv-footer">
    ${variant == BookingPrintVariant.clientConfirmation ? "" : '''<div class="gst-note">
      ✓ Price inclusive of GST @ 5% &nbsp;|&nbsp; SAC: $hsnCode
    </div>'''}
    <div class="terms-title">Terms &amp; Conditions</div>
    <ol class="terms-list">
      <li>The booking advance payment is non-refundable and non-transferable under any circumstances.</li>
      <li>Any additional services requested on the event day will be charged extra as per actual costs.</li>
      <li>The remaining balance must be fully paid on or before the event date prior to service completion.</li>
      <li>Please ensure power supply and standard mirror / lighting setups are available at the service location.</li>
    </ol>
  </div>

</div>
''';
}

String _formatDate(DateTime value) {
  final day = value.day.toString().padLeft(2, '0');
  final month = value.month.toString().padLeft(2, '0');
  return '$day/$month/${value.year}';
}

String _formatMonthYear(DateTime value) {
  const months = [
    'JAN',
    'FEB',
    'MAR',
    'APR',
    'MAY',
    'JUN',
    'JUL',
    'AUG',
    'SEP',
    'OCT',
    'NOV',
    'DEC',
  ];
  return '${months[value.month - 1]} ${value.year}';
}

String _formatLongDate(DateTime value) {
  const months = [
    'January',
    'February',
    'March',
    'April',
    'May',
    'June',
    'July',
    'August',
    'September',
    'October',
    'November',
    'December',
  ];
  return '${months[value.month - 1]} ${value.day}, ${value.year}';
}

String _formatTime(DateTime value) {
  final hour = value.hour % 12 == 0 ? 12 : value.hour % 12;
  final minute = value.minute.toString().padLeft(2, '0');
  final meridiem = value.hour < 12 ? 'AM' : 'PM';
  return '$hour:$minute $meridiem';
}

String _escape(String value) {
  return value
      .replaceAll('&', '&amp;')
      .replaceAll('<', '&lt;')
      .replaceAll('>', '&gt;')
      .replaceAll('"', '&quot;')
      .replaceAll("'", '&#39;');
}

String _detailRow(String label, String value) {
  if (value.trim().isEmpty) return '';
  return '<tr><td>${_escape(label)}</td><td>${_escape(value)}</td></tr>';
}

String _titleCase(String value) {
  if (value.isEmpty) return value;
  return value[0].toUpperCase() + value.substring(1).toLowerCase();
}
